function Counter() {
  const [count, setCount] = useState(0);
  // count is a constant for THIS render, e.g. 0

  function handleClick() {
    setCount(count + 1); // count is still 0 here
    setCount(count + 1); // count is STILL 0 here — not 1!
    setCount(count + 1); // and still 0 here!
    // After this handler: state is 0 + 1 = 1, not 3
  }

  return <button onClick={handleClick}>{count}</button>;
}

function AlertButton() {
  const [message, setMessage] = useState('Hello');

  function handleSend() {
    // message is captured from THIS render's snapshot
    setTimeout(() => {
      alert(message); // always shows the value at the time of the click
    }, 3000);
  }

  return (
    <>
      <input
        value={message}
        onChange={e => setMessage(e.target.value)}
      />
      <button onClick={handleSend}>Send in 3s</button>
    </>
  );
}
// If you type, then click Send, then keep typing:
// The alert will show the message AT THE TIME YOU CLICKED, not what you typed after.

function AlertButton() {
  const [message, setMessage] = useState('Hello');
  const messageRef = useRef(message); // mirror state in a ref

  function handleChange(e) {
    messageRef.current = e.target.value; // keep ref in sync
    setMessage(e.target.value);
  }

  function handleSend() {
    setTimeout(() => {
      // reads the LATEST value, not the snapshot
      alert(messageRef.current);
    }, 3000);
  }

  return (
    <>
      <input value={message} onChange={handleChange} />
      <button onClick={handleSend}>Send in 3s</button>
    </>
  );
}

function Counter() {
  const [count, setCount] = useState(0);

  function handleTripleClick() {
    // Using snapshot (count=0): all three produce count=1
    // setCount(count + 1);
    // setCount(count + 1);
    // setCount(count + 1);

    // Using updater function: chains on latest pending state
    setCount(prev => prev + 1); // 0 → 1
    setCount(prev => prev + 1); // 1 → 2
    setCount(prev => prev + 1); // 2 → 3
    // After this handler: count = 3
  }

  return <button onClick={handleTripleClick}>{count}</button>;
}

// Polling example: increment a counter every second
function Timer() {
  const [ticks, setTicks] = useState(0);

  useEffect(() => {
    const id = setInterval(() => {
      // Updater form: reads the latest ticks, not the snapshot from when
      // the effect ran. Without this, ticks would always be 0.
      setTicks(t => t + 1);
    }, 1000);
    return () => clearInterval(id);
  }, []); // empty deps: effect runs once on mount

  return <p>Ticks: {ticks}</p>;
}

function Form() {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');

  function handleSubmit() {
    setName('Alice');  // schedules new render
    setEmail('a@b.c'); // also scheduled — NOT a separate render
    // name and email are still '' here — snapshots unchanged
    console.log(name, email); // '', ''
    // React batches both updates: one render with name='Alice', email='a@b.c'
  }
}

// Render 1: count = 0
// React attaches: button.onclick = () => setCount(0 + 1)

// After click → Render 2: count = 1
// React attaches: button.onclick = () => setCount(1 + 1)
// (replaces the old handler on the DOM node)

// Each click uses the handler from the most recent render,
// which closes over the most recent snapshot's count.

function handleClick() {
  setCount(count + 1);
  console.log(count); // still old value — snapshot not changed
  // To read the new value, compute it yourself:
  const newCount = count + 1;
  setCount(newCount);
  console.log(newCount); // the value that will be in the next snapshot
}

// WRONG: effect runs once, closes over count=0
useEffect(() => {
  const id = setInterval(() => {
    setCount(count + 1); // count is always 0 here!
  }, 1000);
  return () => clearInterval(id);
}, []); // missing count in deps

// CORRECT option 1: include count in deps (effect re-runs on each change)
useEffect(() => {
  const id = setInterval(() => {
    setCount(count + 1);
  }, 1000);
  return () => clearInterval(id);
}, [count]);

// CORRECT option 2: updater form (no deps needed)
useEffect(() => {
  const id = setInterval(() => {
    setCount(c => c + 1); // reads latest value
  }, 1000);
  return () => clearInterval(id);
}, []);

const [user, setUser] = useState({ name: 'Alice', age: 30 });

// WRONG: mutation doesn't create a new snapshot
user.age = 31; // mutates the snapshot object — no re-render!

// CORRECT: create a new object for the next snapshot
setUser({ ...user, age: 31 }); // triggers re-render with new snapshot

// Annotated render trace
// Render 1 snapshot: { count: 0, name: 'Alice' }
function Profile() {
  const [count, setCount] = useState(0);  // → 0
  const [name, setName] = useState('Alice'); // → 'Alice'

  return (
    <div>
      <p>{name}: {count}</p>                     {/* shows 'Alice: 0' */}
      <button onClick={() => setCount(count + 1)}> {/* captures count=0 */}
        +1
      </button>
      <button onClick={() => setName('Bob')}>      {/* captures name='Alice' */}
        Rename
      </button>
    </div>
  );
}
// After clicking +1: Render 2 with snapshot { count: 1, name: 'Alice' }
// After clicking Rename: Render 3 with snapshot { count: 1, name: 'Bob' }

function ClickTracker() {
  const [count, setCount] = useState(0);

  function handleClick() {
    // All three log calls close over the SAME count
    // They will all print the count at the time of this render
    setTimeout(() => console.log('1s:', count), 1000);
    setTimeout(() => console.log('2s:', count), 2000);
    setTimeout(() => console.log('3s:', count), 3000);
  }

  return <button onClick={handleClick}>Count: {count}</button>;
}

import { startTransition, useState } from 'react';

function SearchPage() {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState([]);

  function handleChange(e) {
    // Urgent: update the input
    setQuery(e.target.value);

    // Low priority: update results (can be interrupted)
    startTransition(() => {
      setResults(getSearchResults(e.target.value));
    });
  }

  // Each render has its own frozen query and results snapshots
  return (
    <>
      <input value={query} onChange={handleChange} />
      <ResultsList items={results} />
    </>
  );
}

// Bug: count will always be 0 in the interval
function BuggyCounter() {
  const [count, setCount] = useState(0);

  useEffect(() => {
    const id = setInterval(() => {
      console.log(count); // always 0 — stale snapshot
      setCount(count + 1); // always sets to 1 — reads stale snapshot
    }, 1000);
    return () => clearInterval(id);
  }, []); // empty deps — effect captures render-0 snapshot

  return <div>{count}</div>;
}

// Fix 1: functional updater — no snapshot read needed
function FixedCounter1() {
  const [count, setCount] = useState(0);

  useEffect(() => {
    const id = setInterval(() => {
      setCount(prev => prev + 1); // reads current queued value, not snapshot
    }, 1000);
    return () => clearInterval(id);
  }, []); // safe — we never read count inside the effect

  return <div>{count}</div>;
}

// Fix 2: add count to deps — effect re-runs and re-captures fresh snapshot
function FixedCounter2() {
  const [count, setCount] = useState(0);

  useEffect(() => {
    const id = setInterval(() => {
      setCount(count + 1); // fresh snapshot each time effect runs
    }, 1000);
    return () => clearInterval(id);
  }, [count]); // cleanup + re-register whenever count changes

  return <div>{count}</div>;
}
